# ------------------------------------------------------------------
# Graph nodes
# ------------------------------------------------------------------
def _nodes() -> list:
    return [
        helper.make_node('Tanh', inputs=['model_input'], outputs=['n0_erf__th']),
        helper.make_node('Erf', inputs=['n0_erf__th'], outputs=['n0_erf__act']),
        helper.make_node('Mul', inputs=['n0_erf__act', 'model_input'], outputs=['n0_erf__out']),
        helper.make_node('BatchNormalization', inputs=['n0_erf__out', 'n100_bcb_pre_bn_scale', 'n100_bcb_pre_bn_bias', 'n100_bcb_pre_bn_mean', 'n100_bcb_pre_bn_var'], outputs=['n100_bcb_bn1'], epsilon=9.999999747378752e-06),
        helper.make_node('Conv', inputs=['n100_bcb_bn1', 'n100_bcb_w', 'n100_bcb_b'], outputs=['n100_bcb_cv'], kernel_shape=[3, 3], pads=[1, 1, 1, 1], strides=[1, 1]),
        helper.make_node('BatchNormalization', inputs=['n100_bcb_cv', 'n100_bcb_post_bn_scale', 'n100_bcb_post_bn_bias', 'n100_bcb_post_bn_mean', 'n100_bcb_post_bn_var'], outputs=['n100_bcb_out'], epsilon=9.999999747378752e-06),
        helper.make_node('Reshape', inputs=['n100_bcb_out', 'n200_rrsh_sfl'], outputs=['n200_rrsh_r1']),
        helper.make_node('Reshape', inputs=['n200_rrsh_r1', 'n200_rrsh_sor'], outputs=['n200_rrsh_out']),
        helper.make_node('Pad', inputs=['n200_rrsh_out', 'n300_pem_pads'], outputs=['n300_pem_out'], mode='edge'),
        helper.make_node('Mul', inputs=['n300_pem_out', 'n300_pem_out'], outputs=['n400_msp_sq']),
        helper.make_node('Add', inputs=['n400_msp_sq', 'n400_msp_eps'], outputs=['n400_msp_add']),
        helper.make_node('Sqrt', inputs=['n400_msp_add'], outputs=['n400_msp_sq2']),
        helper.make_node('Mul', inputs=['n400_msp_sq2', 'n400_msp_scale'], outputs=['n400_msp_out']),
    ]

# ------------------------------------------------------------------
# Model builder
# ------------------------------------------------------------------
def build_model() -> bytes:
    inputs_info  = [helper.make_tensor_value_info(INPUT_NAME, TensorProto.FLOAT, INPUT_SHAPE)]
    outputs_info = [helper.make_tensor_value_info(OUTPUT_NAME, TensorProto.FLOAT, OUTPUT_SHAPE)]
    graph = helper.make_graph(_nodes(), "bug_000372", inputs_info, outputs_info, initializer=_inits())
    model = helper.make_model(graph, opset_imports=[helper.make_opsetid("", OPSET)])
    model.ir_version = IR_VERSION
    return model.SerializeToString()


